import React, { useState } from 'react';

const BookingForm = ({ property, onBook }) => {
    const [checkIn, setCheckIn] = useState('');
    const [checkOut, setCheckOut] = useState('');
    const [guests, setGuests] = useState(1);

    const handleSubmit = (e) => {
        e.preventDefault();
        onBook({ checkIn, checkOut, guests });
    };

    const calculateTotal = () => {
        if (!checkIn || !checkOut) return 0;
        const start = new Date(checkIn);
        const end = new Date(checkOut);
        const nights = Math.ceil((end - start) / (1000 * 60 * 60 * 24));
        return nights > 0 ? nights * property.pricePerNight : 0;
    };

    const total = calculateTotal();

    return (
        <div className="bg-white rounded-xl shadow-xl border border-gray-200 p-6 sticky top-24 z-10">
            <div className="flex justify-between items-end mb-6">
                <div>
                    <span className="text-2xl font-bold text-gray-900">₹{property.pricePerNight}</span>
                    <span className="text-gray-500"> / night</span>
                </div>
                <div className="flex items-center gap-1 text-sm">
                    <span className="font-bold">★ {property.rating || 'New'}</span>
                </div>
            </div>

            <form onSubmit={handleSubmit} className="space-y-4">
                <div className="grid grid-cols-2 gap-2">
                    <div className="border rounded-lg p-3">
                        <label className="block text-xs font-bold uppercase text-gray-500">Check-in</label>
                        <input
                            type="date"
                            required
                            className="w-full text-sm outline-none mt-1"
                            value={checkIn}
                            onChange={(e) => setCheckIn(e.target.value)}
                        />
                    </div>
                    <div className="border rounded-lg p-3">
                        <label className="block text-xs font-bold uppercase text-gray-500">Check-out</label>
                        <input
                            type="date"
                            required
                            className="w-full text-sm outline-none mt-1"
                            value={checkOut}
                            onChange={(e) => setCheckOut(e.target.value)}
                        />
                    </div>
                </div>

                <div className="border rounded-lg p-3">
                    <label className="block text-xs font-bold uppercase text-gray-500">Guests</label>
                    <input
                        type="number"
                        min="1"
                        max={property.maxGuests}
                        required
                        className="w-full text-sm outline-none mt-1"
                        value={guests}
                        onChange={(e) => setGuests(e.target.value)}
                    />
                </div>

                <button
                    type="submit"
                    className="w-full bg-rose-600 hover:bg-rose-700 text-white font-bold py-3 rounded-lg transition-colors"
                >
                    Reserve
                </button>
            </form>

            {total > 0 && (
                <div className="mt-6 pt-6 border-t border-gray-100 space-y-3">
                    <div className="flex justify-between text-gray-600">
                        <span>₹{property.pricePerNight} x {total / property.pricePerNight} nights</span>
                        <span>₹{total}</span>
                    </div>
                    <div className="flex justify-between text-gray-600">
                        <span>Service fee</span>
                        <span>₹{Math.round(total * 0.1)}</span>
                    </div>
                    <div className="flex justify-between font-bold text-lg pt-3 border-t border-gray-100">
                        <span>Total</span>
                        <span>₹{total + Math.round(total * 0.1)}</span>
                    </div>
                </div>
            )}
        </div>
    );
};

export default BookingForm;
